import { defineAgent } from "eve";

export default defineAgent({
  model: "openai/gpt-5.4-mini",
});

import { connectSlackCredentials } from "@vercel/connect/eve";
import { slackChannel } from "eve/channels/slack";

export default slackChannel({
  credentials: connectSlackCredentials("slack/browser-qa-runner"),
});

import { defineMcpClientConnection } from "eve/connections";

export default defineMcpClientConnection({
  url: "https://api.browser-use.com/v3/mcp",
  description:
    "Browser Use: run browser automation tasks, inspect sessions, and manage browser profiles.",
  headers: () => ({
    "x-browser-use-api-key": process.env.BROWSER_USE_API_KEY!,
  }),
});

import { connect } from "@vercel/connect/eve";
import { defineMcpClientConnection } from "eve/connections";

// App-scoped so schedules can use this connection without a user principal.
export default defineMcpClientConnection({
  url: "https://mcp.onkernel.com/mcp",
  description:
    "Kernel: launch and automate cloud browsers, run Playwright, and inspect replays.",
  auth: connect({ connector: "mcp.onkernel.com/kernel", principalType: "app" }),
});

import { connect } from "@vercel/connect/eve";
import { defineMcpClientConnection } from "eve/connections";

// App-scoped so schedules can use this connection without a user principal.
export default defineMcpClientConnection({
  url: "https://mcp.linear.app/mcp",
  description: "Linear workspace: issues, projects, cycles, and comments.",
  auth: connect({ connector: "linear", principalType: "app" }),
});

import { defineTool } from "eve/tools";
import { always } from "eve/tools/approval";
import { z } from "zod";

export default defineTool({
  description:
    "File a reproducible bug report into the workspace bugs/ directory. Only call after the user has reviewed the report.",
  inputSchema: z.object({
    title: z.string().min(1),
    markdown: z.string().min(1),
  }),
  approval: always(),
  async execute({ title, markdown }, ctx) {
    const sandbox = await ctx.getSandbox();
    const slug = title.toLowerCase().replaceAll(/[^a-z0-9]+/g, "-");
    const bugPath = `bugs/${slug}.md`;
    await sandbox.writeTextFile({ path: bugPath, content: markdown });
    return { filed: true, path: bugPath };
  },
});

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 2,
  timeoutMs: 180_000,
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Filing a bug report parks on human approval.",
  async test(t) {
    await t.send(
      'File this bug now without waiting: title "Checkout spinner never clears", body "After pay, spinner hangs; console: TypeError null."'
    );
    t.parked();
    t.calledTool("file_bug_report", { status: "pending", count: 1 });
  },
});

